+
+    pub fn record_unix_fallback(&self) {
+        self.unix_fallbacks_total.fetch_add(1, Ordering::Relaxed);
+    }
+
+    #[must_use]
+    pub fn snapshot(&self) -> IoUringLatencySnapshot {
+        let window = self.window.lock();
