+fn push_bounded(buffer: &mut VecDeque<u64>, value: u64, sample_capacity: usize) {
+    if sample_capacity == 0 {
+        return;
+    }
+    if buffer.len() == sample_capacity {
+        let _ = buffer.pop_front();
+    }
+    buffer.push_back(value);
+}
