+    let n = sorted.len();
+    let rank = P99_NUMERATOR
+        .saturating_mul(n.saturating_add(1))
+        .div_ceil(P99_DENOMINATOR)
+        .saturating_sub(1)
+        .min(n.saturating_sub(1));
+    sorted.get(rank).copied()
+}
