+/// or `[`), or is not a string literal.
+fn extract_glob_prefix(pattern: &Expr) -> Option<String> {
+    if let Expr::Literal(Literal::String(s), _) = pattern {
+        let mut prefix = String::new();
+        for ch in s.chars() {
+            if matches!(ch, '*' | '?' | '[') {
+                break;
+            }
+            prefix.push(ch);
+        }
+        if prefix.is_empty() {
+            None
+        } else {
+            Some(prefix)
+        }
+    } else {
